-- Strip the 'Course Objectives' and 'Disclaimer' sections from the
-- product short_description across all stores. Generated by a one-off
-- PHP script (see git history for the generator); committed as static
-- UPDATEs so apply.php can run it deterministically on every env.
-- Stops at the next <h1-6> or <strong> heading so sibling sections
-- (Learning Outcomes, Course Brochure, etc.) are left intact.
-- Idempotent: rerunning is a no-op once the markers are gone.

UPDATE catalog_product_entity_text SET value='<p>Elevate your digital design journey with our Photoshop CC Essential Training at Tertiary Courses. This meticulously curated program dives deep into the foundational aspects of Photoshop, providing keen insights into image resizing, cropping, and the nuanced world of layers. Whether reshaping visuals through transformations or understanding the benefits of Smart Objects, we ensure you acquire the skills to make your digital visions come to life.</p>\n<p>Master the art of layer masks, empowering you to craft intricate designs seamlessly. The course will guide you through making accurate selections, optimizing the image editing process, and infusing your projects with adjustment layers for that perfect finish. Step into a world where your digital design dreams and Photoshop''s vast capabilities intersect, and leave with a renewed confidence in your graphic editing prowess.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p class="p1">No funding is available for this course.</p>\n<p>For WSQ funding, please checkout the details at&nbsp;<span style="text-decoration: underline;"><a href="https://www.tertiarycourses.com.sg/wsq-digital-image-production-with-photoshop.html" title="WSQ - WSQ - Professional Digital Image Editing with Photoshop\n">WSQ - Professional Digital Image Editing with Photoshop</a></span><span style="text-decoration: underline;"></span></p>\n</div>' WHERE value_id=513;
UPDATE catalog_product_entity_text SET value='<p>Unlock the vast potentials of Adobe InDesign CC with our tailored Essential Training. Designed for both beginners and professionals, this course offers a comprehensive journey from the basics, like getting acquainted with the user interface, to advanced design techniques. Within just 30 minutes, embark on a hands-on experience, setting up new documents, and effortlessly placing graphics, ensuring every project reflects impeccable design standards.</p>\n<p>Delve deeper into the nuances of color swatches, layers, and object transformation to bring your design visions to life. Learn the art of creating engaging multidocument books, interactive PDFs, and exporting to EPUB, ensuring each document stands out. With a special focus on document proofing using the Preflight panel and effective printing and exporting strategies, this training ensures you''re equipped with the skills to navigate InDesign CC efficiently, making every design project a masterpiece.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p class="p1">No funding is available for this course.</p>\n<p>For WSQ funding, please checkout the details at&nbsp;<span style="text-decoration: underline;"><a href="https://www.tertiarycourses.com.sg/wsq-digital-drawing-indesign-course.html" title="WSQ - Creating Stunning Print and Digital Publications with InDesign">WSQ - Creating Stunning Print and Digital Publications with InDesign</a></span><span style="text-decoration: underline;"></span></p>\n</div>' WHERE value_id=708;
UPDATE catalog_product_entity_text SET value='<p>Unlock the full potential of cloud-based accounting with our QuickBooks Online Plus Training at Tertiary Courses. Designed for both beginners and seasoned accountants, this course takes you through the intricate features of the renowned software. Learn the nuances of setting up accounts, managing customers and vendors, and delve deep into products, services, and billable expenses. Whether it''s time tracking, handling refunds, or automating transactions, this training ensures you''re adept in every facet of QuickBooks Online.</p>\n<p>Efficiently manage your financial tasks, from paying bills, creating invoices to setting up online banking accounts, and generating insightful reports. With expert guidance on sales tax and the automation of recurring transactions, you''ll be well-equipped to streamline your financial processes, saving both time and effort. Immerse in this transformative training, ensuring that your financial management, whether for personal or business purposes, reaches new heights of precision and efficiency.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p class="p1">No funding is available for this course.</p>\n<p>For WSQ funding, please checkout the details at&nbsp;<span style="text-decoration: underline;"><a href="https://www.tertiarycourses.com.sg/wsq-quickbooks-online-plus-course.html" title="WSQ Quickbooks Course">WSQ - Quickbooks Accounting System for Small and Medium Enterprise</a></span><span style="text-decoration: underline;"></span></p>\n</div>\n' WHERE value_id=3437;
UPDATE catalog_product_entity_text SET value='<p>Unlock the full potential of cloud database technology with our comprehensive Google Professional Cloud Database Engineer course. This program offers an in-depth journey through the intricacies of designing, building, and maintaining databases on the Google Cloud Platform (GCP). Aimed at database professionals looking to leverage Google Cloud&rsquo;s powerful database services, this course will prepare you for the official Google certification with a strong emphasis on practical skills for real-world applications. Participants will delve into key topics such as cloud database architectures, storage options, and the dynamics of managing scalable and reliable data solutions that support enterprise operations.</p>\n<p>Our expert-led training is focused not only on passing the exam but also on ensuring that you can apply your knowledge immediately, with insights on integrating GCP databases within the Shopee ecosystem. By the end of this course, you will be adept at implementing, configuring, and troubleshooting GCP&rsquo;s database services, and you&rsquo;ll be ready to step into a role that requires advanced knowledge of cloud-based database solutions. Whether you are a seasoned IT professional or an aspiring cloud specialist, this course is your stepping stone to becoming a sought-after Google Professional Cloud Database Engineer, capable of transforming business data strategies into scalable successes.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n\n<h2>Register for Google Cloud Certification</h2>\n<p>Once you are prepared for the exam, you can register for the certification <span style="text-decoration: underline;"><a href="https://cloud.google.com/learn/certification?hl=en" title="Google Cloud Certification" target="_blank">here</a></span>.&nbsp;We are&nbsp; Kryterion Authorized Testing Center. You can take the certification exam at our test center. Note that the course fee does not include the certification exam fee.&nbsp;</p>\n\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p>No funding is available for this course</p>\n</div>' WHERE value_id=4166;
UPDATE catalog_product_entity_text SET value='<p>Embark on a path to becoming a Google Professional Cloud Network Engineer with our dedicated certification prep course. This training is strategically designed for network professionals aiming to deepen their understanding of cloud-based networking on Google Cloud Platform (GCP). You''ll explore the intricacies of designing, planning, and implementing secure and scalable network architectures using GCP services. Our curriculum delves into critical aspects like network security, hybrid cloud configurations, and optimizing network performance, equipping you with the skills required to effectively manage and troubleshoot GCP networks.</p>\n<p>As part of this course, you will engage in practical, hands-on learning experiences that bring theoretical concepts to life. Guided by seasoned instructors, you will navigate through the complexities of GCP''s networking features, from virtual private clouds (VPCs) to load balancing and network connectivity options. The course is not just focused on helping you pass the certification exam but also aims to enhance your practical networking skills that can be directly applied in your current or future roles. Whether you''re looking to validate your expertise with a Google Cloud certification or aspiring to take on more advanced network engineering responsibilities, this course offers the comprehensive training and resources you need to succeed. Enroll now and take a significant step forward in your cloud networking career.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n\n<h2>Register for Google Cloud Certification</h2>\n<p>Once you are prepared for the exam, you can register for the certification <span style="text-decoration: underline;"><a href="https://cloud.google.com/learn/certification?hl=en" title="Google Cloud Certification" target="_blank">here</a></span>.&nbsp;We are&nbsp; Kryterion Authorized Testing Center. You can take the certification exam at our test center. Note that the course fee does not include the certification exam fee.&nbsp;</p>\n\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p>No funding is available for this course</p>\n</div>' WHERE value_id=4230;
UPDATE catalog_product_entity_text SET value='<p>Embark on a transformative journey in digital design with the Illustrator CC Essential Training at Tertiary Courses. This comprehensive program covers everything from the basics of artboards, layers, and fundamental shapes, to the intricacies of scaling, rotating, and coloring objects. Whether you''re honing your skills in spot colors, swatches, or diving into the depths of the Appearance panel, we offer the tools and techniques to bring your design visions to life.</p>\n<p>Unleash your creativity through compound paths, brush tools, and the powerful Pen tool, enabling intricate vector drawings. Delight in the realms of typography, embed stunning images, and ensure your creations are print-ready or easily exportable for diverse platforms. Join us, as we illuminate the path to mastering Illustrator CC, ensuring you emerge as a confident and competent graphic design maestro.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p class="p1">No funding is available for this course.</p>\n<p>For WSQ funding, please checkout the details at&nbsp;<span style="text-decoration: underline;"><a href="https://www.tertiarycourses.com.sg/wsq-digital-graphics-design-illustrator.html" title="WSQ - Creating Professional Graphics with Adobe Illustrator">WSQ - Creating Professional Graphics with Adobe Illustrator</a></span><span style="text-decoration: underline;"></span></p>\n</div>' WHERE value_id=4258;
UPDATE catalog_product_entity_text SET value='<p>Step into the world of cloud computing with our Google Cloud Digital Leader Learning Path Certification Prep course. This program is expertly designed for professionals seeking to harness the full potential of Google Cloud technologies in driving digital transformation. Our course provides a deep dive into the essentials of cloud computing, focusing on Google Cloud''s innovative solutions and services. You will learn the fundamentals of cloud architecture, data analytics, and machine learning, equipping you with the knowledge to make informed decisions on cloud technology adoption and implementation.</p>\n<p>Through this course, you will develop the skill set necessary to become a confident Digital Leader in today''s tech-driven business environment. Our experienced instructors will guide you through the core concepts of Google Cloud, ensuring you grasp the strategic approaches to cloud solutions and data management. The curriculum is structured to not only prepare you for the Google Cloud Digital Leader certification but also to enhance your practical understanding for immediate application in your professional journey. Join us to become a pivotal part of your organization''s digital transformation, mastering the strategies to leverage cloud technologies effectively. Enroll now and take a significant step towards becoming a certified Google Cloud Digital Leader.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n\n<h2>Register for Google Cloud Certification</h2>\n<p>Once you are prepared for the exam, you can register for the certification <span style="text-decoration: underline;"><a href="https://cloud.google.com/learn/certification?hl=en" title="Google Cloud Certification" target="_blank">here</a></span>.&nbsp;We are&nbsp; Kryterion Authorized Testing Center. You can take the certification exam at our test center. Note that the course fee does not include the certification exam fee.&nbsp;</p>\n\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p>No funding is available for this course</p>\n</div>' WHERE value_id=4286;
UPDATE catalog_product_entity_text SET value='<p>Embark on a transformative journey towards becoming a Google Cloud Certified Professional Google Workspace Administrator with our meticulously designed exam preparation course. This program is tailored for IT professionals seeking to validate their expertise in configuring, managing, and securing Google Workspace services. By enrolling in this course, you will gain in-depth knowledge of Google Workspace''s core services, including Gmail, Calendar, Docs, and Drive, and learn how to efficiently manage users and resources. Our expert instructors, equipped with hands-on experience, will guide you through the nuances of administering a Google Workspace environment, ensuring you''re well-prepared to tackle the certification exam with confidence.</p>\n<p>The curriculum is structured to cover all essential aspects of the exam, including user management, service configuration, security settings, and compliance protocols. Through a blend of theoretical knowledge and practical exercises, you will develop a robust understanding of how to leverage Google Workspace to streamline communication, enhance collaboration, and boost productivity within your organization. This course is an invaluable investment for IT professionals aiming to leverage cloud technologies for business growth, providing you with the skills and accreditation needed to stand out in the competitive IT job market.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n\n<h2>Register for Google Cloud Certification</h2>\n<p>Once you are prepared for the exam, you can register for the certification <span style="text-decoration: underline;"><a href="https://cloud.google.com/learn/certification?hl=en" title="Google Cloud Certification" target="_blank">here</a></span>.&nbsp;We are&nbsp; Kryterion Authorized Testing Center. You can take the certification exam at our test center. Note that the course fee does not include the certification exam fee.&nbsp;</p>\n\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p>No funding is available for this course</p>\n</div>' WHERE value_id=4352;
UPDATE catalog_product_entity_text SET value='<p>Unlock the potential of 3D design with our SketchUp Essential Training at Tertiary Courses. This comprehensive course is designed to immerse participants into the world of SketchUp, providing hands-on experience and understanding of its powerful features. Begin by learning to craft precise camera views, shade faces and edges, and manipulate objects through selection, movement, scaling, and rotation. Explore foundational drawing techniques, from creating circles and polygons to adding depth with 3D text, and enhance your sketches with detailed labeling.</p>\n<p>Our tailored curriculum further delves into the essentials of working with layers, integrating components from the 3D Warehouse, and the art of applying materials to breathe life into your designs. Mapping textures effectively and understanding the nuances of exporting sketches in both 2D and 3D formats will ensure participants leave equipped with a well-rounded set of skills. Whether you''re an aspiring designer or a seasoned professional, this course will refine your abilities, setting you on the path to SketchUp mastery.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p class="p1">No funding is available for this course.</p>\n<p>For WSQ funding, please checkout the details at&nbsp;<span style="text-decoration: underline;"><a href="https://www.tertiarycourses.com.sg/wsq-technical-drawing-sketchup.html" title="WSQ - Basic Technical Drawing with Sketchup for Beginners">WSQ - Basic Technical Drawing with Sketchup for Beginners</a></span><span style="text-decoration: underline;"></span></p>\n</div>' WHERE value_id=4620;
UPDATE catalog_product_entity_text SET value='<p>Unearth the power of Adobe''s After Effects CC with our detailed Essential Training. From novices looking to grasp the basics to seasoned professionals aiming to polish their skills, this course offers insights into the world of advanced video editing. Participants will be introduced to fundamental video terminology, enabling a clear understanding of the intricate facets of the editing landscape. The journey further delves into creating compelling compositions, mastering the art of using layers, masks, blend modes, and understanding the pivotal role of track mattes.</p>\n<p>With a focus on real-world applications, attendees will gain hands-on experience in building complex visual objects with Pre-compose, explore the ray-traced 3D renderer''s capabilities, and create enthralling 3D projects from Illustrator files. The course also sheds light on refining scenes through optimal lighting, animating captivating type on paths, utilizing Keylight for pristine green-screen footage, and the meticulous craft of rotoscoping. By the course''s culmination, learners will be well-equipped to create visually arresting video projects, setting them apart in the dynamic world of video editing and production.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p class="p1">No funding is available for this course.</p>\n<p>For WSQ funding, please checkout the details at&nbsp;<span style="text-decoration: underline;"><a href="https://www.tertiarycourses.com.sg/wsq-video-editing-with-after-effects-course.html" title="WSQ - Compositing and Visual Effects with After Effects">WSQ - Compositing and Visual Effects with After Effects</a></span><span style="text-decoration: underline;"></span></p>\n</div>' WHERE value_id=4658;
UPDATE catalog_product_entity_text SET value='<p>This course is designed to teach beginners the fundamentals of Adobe Lightroom, a powerful photo editing software that enables photographers to organize, edit, and share their images efficiently. Students will learn the basic interface and tools of Lightroom, as well as how to import, organize and manage their photos.</p>\n<p>The course will also cover the fundamental editing tools such as exposure, contrast, color balance, sharpening and noise reduction, as well as advanced techniques such as local adjustments and retouching. Students will learn how to apply these tools to improve their images, create their own presets and synchronize their edits across multiple images.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>\n<div style=" width: 100%; padding: 10px; border-radius: 25px;">\n<h2>Funding and Grant Applications</h2>\n<p class="p1">No funding is available for this course.</p>\n<p>For WSQ funding, please checkout the details at&nbsp;<span style="text-decoration: underline;"><a href="https://www.tertiarycourses.com.sg/wsq-digital-image-production-with-lightroom.html" title="WSQ - Mastering Adobe Lightroom for Photo Editing">WSQ - Mastering Adobe Lightroom for Photo Editing</a></span><span style="text-decoration: underline;"></span></p>\n</div>' WHERE value_id=6106;
UPDATE catalog_product_entity_text SET value='<p>Unlock the potential of 3D design with our SketchUp Essential Training at Tertiary Courses. This comprehensive course is designed to immerse participants into the world of SketchUp, providing hands-on experience and understanding of its powerful features. Begin by learning to craft precise camera views, shade faces and edges, and manipulate objects through selection, movement, scaling, and rotation. Explore foundational drawing techniques, from creating circles and polygons to adding depth with 3D text, and enhance your sketches with detailed labeling.</p>\n<p>Our tailored curriculum further delves into the essentials of working with layers, integrating components from the 3D Warehouse, and the art of applying materials to breathe life into your designs. Mapping textures effectively and understanding the nuances of exporting sketches in both 2D and 3D formats will ensure participants leave equipped with a well-rounded set of skills. Whether you''re an aspiring designer or a seasoned professional, this course will refine your abilities, setting you on the path to SketchUp mastery.</p>\n<h2>Certificate</h2>\n<p>All participants will receive a Certificate of Completion from Tertiary Courses after achieved at least 75% attendance.</p>' WHERE value_id=9419;
